#include <iostream>
#include <chrono>

int main() {
    using namespace std::chrono;

    year_month_day valid{year{2024}, month{2}, day{29}};   // 2024 سنة كبيسة
    year_month_day invalid{year{2023}, month{2}, day{29}};  // 2023 ليست كبيسة

    std::cout << "29/2/2024 صالح: " << valid.ok() << '\n';     // true
    std::cout << "29/2/2023 صالح: " << invalid.ok() << '\n';   // false

    // يمكن تصحيحه بـ operator+
    auto corrected = year{2023}/month{3}/day{1};
    std::cout << "تصحيح: " << corrected.ok() << '\n'; // true
}

