#include <iostream>
#include <chrono>

int main() {
    using namespace std::chrono;

    // التاريخ الحالي
    auto today = floor<days>(system_clock::now());
    weekday today_wd{today};

    // حساب الأيام حتى الجمعة القادمة
    days until_friday = Friday - today_wd;
    if (until_friday == days{0}) until_friday = days{7};

    auto next_friday = today + until_friday;
    year_month_day friday_date{next_friday};

    std::cout << "الجمعة القادمة: "
              << static_cast<int>(friday_date.year()) << '-'
              << static_cast<unsigned>(friday_date.month()) << '-'
              << static_cast<unsigned>(friday_date.day()) << '\n';
}

