#include <iostream>
#include <chrono>

int main() {
    using namespace std::chrono;

    auto sys = system_clock::now();
    auto utc = clock_cast<utc_clock>(sys);
    auto tai = clock_cast<tai_clock>(sys);
    auto gps = clock_cast<gps_clock>(sys);

    // TAI = UTC + leap seconds (≈ 37 ثانية في 2024)
    // GPS = UTC + leap seconds - 9 ثوان
    std::cout << "SYS: " << sys << '\n';
    std::cout << "UTC: " << utc << '\n';
    std::cout << "TAI: " << tai << '\n';
    std::cout << "GPS: " << gps << '\n';
}

#include <iostream>
