    // آخر يوم في فبراير 2024 (سنة كبيسة)
    auto feb_2024 = year{2024}/February/last_day;
    std::cout << "فبراير 2024: " << static_cast<unsigned>(feb_2024.day()) << " يوم" << '\n'; // 29

