    std::cout << "فبراير 2023: " << static_cast<unsigned>(feb_2023.day()) << " يوم" << '\n'; // 28

    // آخر يوم في ديسمبر
    auto dec = year{2024}/December/last_day;
    std::cout << "ديسمبر 2024: " << static_cast<unsigned>(dec.day()) << " يوم" << '\n'; // 31
}

