std::duration_cast.example:
// مثال: تحويل مدة زمنية بين وحدات مختلفة
#include <chrono>
#include <iostream>
int main() {
    using namespace std::chrono;
    milliseconds ms{2500};
    // تحويل مللي ثانية لثوانٍ (يُفقد الجزء الكسري)
    auto sec = duration_cast<seconds>(ms);
    std::cout << sec.count() << " ثوانٍ\n"; // 2
    // تحويل مللي ثانية لدقائق
    auto min = duration_cast<minutes>(ms);
    std::cout << min.count() << " دقائق\n"; // 0
}

