// مثال: استخدام الساعات لقياس فترات طويلة
#include <chrono>
#include <iostream>
int main() {
    using namespace std::chrono;
    hours flight_time{8};
    hours layover{2};
    hours total = flight_time + layover;
    std::cout << "إجمالي الرحلة: " << total.count() << " ساعات\n"; // 10
    // تحويل لدقائق
    auto mins = duration_cast<minutes>(total);
    std::cout << mins.count() << " دقيقة\n"; // 600
}

