// مثال: حساب وقت انتهاء صلاحية جلسة
#include <chrono>
#include <iostream>
int main() {
    using namespace std::chrono;
    minutes session_timeout{30};
    minutes elapsed{12};
    minutes remaining = session_timeout - elapsed;
    std::cout << "الوقت المتبقي: " << remaining.count() << " دقيقة\n"; // 18
    // تحويل لثوانٍ
    std::cout << duration_cast<seconds>(remaining).count() << " ثانية\n"; // 1080
}

std::nanoseconds.example:
// مثال: قياس زمن عملية حسابية بسيطة بالنانوثانية
#include <chrono>
#include <iostream>
int main() {
    using namespace std::chrono;
    auto start = steady_clock::now();
    volatile long sum = 0;
    for (int i = 0; i < 1000000; ++i) sum += i;
    auto end = steady_clock::now();
    auto elapsed = duration_cast<nanoseconds>(end - start);
    std::cout << "الوقت: " << elapsed.count() << " نانوثانية\n";
}

